reverseString:
import std.stdio;
import std.string; // for representation, etc.
import std.array;   // for array properties/functions like .dup
import std.range;   // for retro
import std.utf;     // for Unicode correctness

void main() {
    string original = "Hello D!";

    // Method 1: Using retro (works on ranges, including strings)
    // Creates a reversed range, needs conversion back to string/array
    // This is generally efficient and handles UTF-8 correctly.
    string reversedRetro = cast(string) original.retro().array;
    writeln("Original: ", original);
    writeln("Reversed (retro): ", reversedRetro);

    // Method 2: Manual reverse using array operations (UTF-8 safe)
    // Convert to dchar array (UTF-32) for easy indexing/swapping
    dchar[] dchars = original.to!dchar; // std.utf
    size_t n = dchars.length;
    for (size_t i = 0; i < n / 2; ++i) {
        swap(dchars[i], dchars[n - 1 - i]); // std.algorithm.mutation needed for swap? No, built-in swap works for arrays
    }
    string reversedManual = to!string(dchars); // std.conv : to
    writeln("Reversed (manual UTF-32): ", reversedManual);

    // Example with Unicode
    string originalUnicode = "你好 D语言"; // Example Unicode
    string reversedUnicode = cast(string) originalUnicode.retro().array;
    writeln("Original Unicode: ", originalUnicode);
    writeln("Reversed Unicode: ", reversedUnicode);
}

fibonacci:
import std.stdio;
import std.bigint; // For potentially very large Fibonacci numbers

// Function to calculate the Nth Fibonacci number (0-indexed) iteratively
// Returns BigInt to handle potential overflow
BigInt fibonacci(int n) {
    if (n < 0) {
        throw new Exception("Fibonacci input must be non-negative");
    }
    if (n == 0) return BigInt(0);
    if (n == 1) return BigInt(1);

    BigInt a = 0;
    BigInt b = 1;
    foreach (i; 2 .. n + 1) {
        BigInt next = a + b;
        a = b;
        b = next;
    }
    return b;
}

// Function to generate first N Fibonacci numbers
BigInt[] generateFibonacciSequence(int count) {
     if (count < 0) {
        throw new Exception("Count must be non-negative");
    }
    BigInt[] sequence;
    sequence.length = count; // Pre-allocate
    foreach(i; 0 .. count) {
        sequence[i] = fibonacci(i);
    }
    return sequence;
}

void main() {
    int n = 10;
    writeln("Fibonacci number F(", n, "): ", fibonacci(n));

    int count = 15;
    writeln("First ", count, " Fibonacci numbers:");
    writeln(generateFibonacciSequence(count));

    // Larger number example
    int largeN = 90; // Well beyond 64-bit integer limit
    writeln("Fibonacci number F(", largeN, "): ", fibonacci(largeN));
}

