import std.stdio;
import std.bigint; // Use BigInt for factorials > 20

// Function to calculate factorial N!
BigInt factorial(int n) {
    if (n < 0) {
        throw new Exception("Factorial is not defined for negative numbers.");
    }
    BigInt result = 1;
    // No need for explicit loop for n=0, result starts at 1
    foreach (i; 1 .. n + 1) {
        // BigInt handles overflow automatically
        result *= i;
    }
    return result;
}

void main() {
    int num = 5;
    writeln("Factorial of ", num, " is: ", factorial(num));

    num = 0;
    writeln("Factorial of ", num, " is: ", factorial(num));

    num = 20; // Max for 64-bit unsigned int
    writeln("Factorial of ", num, " is: ", factorial(num));

    num = 21; // Requires BigInt
    writeln("Factorial of ", num, " is: ", factorial(num));

