primeCheck:
import std.stdio;
import std.math; // For isqrt

// Function to check if a number is prime
bool isPrime(long n) { // Use long to handle larger numbers
    if (n <= 1) {
        return false; // Primes must be > 1
    }
    if (n <= 3) {
        return true; // 2 and 3 are prime
    }
    if (n % 2 == 0 || n % 3 == 0) {
        return false; // Divisible by 2 or 3
    }

    // Check divisors from 5 upwards, stepping by 6
    long i = 5;
    long limit = isqrt(n); // Integer square root from std.math

    while (i <= limit) {
        if (n % i == 0 || n % (i + 2) == 0) {
            return false; // Divisor found
        }
        i += 6;
    }

    return true; // No divisors found
}

void main() {
    long[] numbersToCheck = [2, 3, 4, 17, 25, 29, 97, 100, 1, -5, 1_000_000_007]; // 1,000,000,007 is prime

    foreach (n; numbersToCheck) {
        if (isPrime(n)) {
            writeln(n, " is prime.");
        } else {
            writeln(n, " is not prime.");
        }
    }
}

