import std.stdio;
import std.file; // For write, append, exists, remove

void main() {
    string filename = "output_d.txt";
    string line1 = "First line written using D's std.file.";
    string line2 = "This is the second line.";
    string lineAppend = "This line was appended.";

    // --- Write using std.file.write (overwrites or creates) ---
    writeln("--- Writing to '", filename, "' using write (overwrite) ---");
    try {
        // Combine lines with newline characters
        string initialContent = line1 ~ "\\n" ~ line2 ~ "\\n";
        write(filename, initialContent); // Writes the entire string
        writeln("Successfully wrote initial content.");
    } catch (FileException e) {
        stderr.writeln("Error writing to '", filename, "': ", e.msg);
    }

    // --- Append using std.file.append ---
    writeln("\\n--- Appending to '", filename, "' using append ---");
    try {
        // Append requires data as bytes usually, convert string to ubyte[]
        // Or append can take string directly depending on version/overload
        append(filename, lineAppend ~ "\\n"); // Append string + newline
        writeln("Successfully appended content.");
    } catch (FileException e) {
        stderr.writeln("Error appending to '", filename, "': ", e.msg);
    }

    // --- Display final content (by reading it back) ---
    writeln("\\n--- Final content of '", filename, "': ---");
    if (exists(filename) && isFile(filename)) {
        try {
            write(readText(filename)); // Display content
        } catch (Exception e) {
            stderr.writeln("Error reading back file: ", e.msg);
        }
    } else {
        stderr.writeln("File '", filename, "' not found for display.");
    }

    // Optional: Clean up
    // if (exists(filename)) { remove(filename); }
}

