import std.stdio;
import std.file; // For exists, isFile, isDir

void main() {
    string fileToCheck = "d_exists_test.d"; // Example file
    string dirToCheck = "my_d_dir";         // Example directory
    string nonExistent = "no_such_d_thing.ext";

    // Create dummy file/dir
    try {
        write(fileToCheck, "// D test file"); // Create file
        mkdir(dirToCheck); // Create directory std.file.mkdir
        writeln("Created dummy file '", fileToCheck, "' and directory '", dirToCheck, "'");

        writeln("\\n--- Checking Existence and Type ---");

        // std.file.exists(path) - Checks if path exists (file, dir, link etc.)
        writeln("'", fileToCheck, "' exists? ", exists(fileToCheck));
        writeln("'", dirToCheck, "' exists? ", exists(dirToCheck));
        writeln("'", nonExistent, "' exists? ", exists(nonExistent));

        // std.file.isFile(path) - Checks if path exists AND is a regular file
        writeln("\\n'", fileToCheck, "' is file? ", isFile(fileToCheck));
        writeln("'", dirToCheck, "' is file? ", isFile(dirToCheck)); // Should be false

        // std.file.isDir(path) - Checks if path exists AND is a directory
        writeln("\\n'", fileToCheck, "' is directory? ", isDir(fileToCheck)); // Should be false
        writeln("'", dirToCheck, "' is directory? ", isDir(dirToCheck));

        // Clean up
        remove(fileToCheck);
        rmdir(dirToCheck); // std.file.rmdir
        writeln("\\nCleaned up dummy file and directory.");

    } catch (FileException e) {
        stderr.writeln("File operation error: ", e.msg);
        // Attempt cleanup
        if (exists(fileToCheck)) { remove(fileToCheck); }
        if (exists(dirToCheck)) { rmdir(dirToCheck); }
    } catch (Exception e) {
        stderr.writeln("An unexpected error occurred: ", e.msg);
        if (exists(fileToCheck)) { remove(fileToCheck); }
        if (exists(dirToCheck)) { rmdir(dirToCheck); }
    }
}

