import std.stdio;
import std.datetime.systime; // For Clock.currTime
import std.datetime.timezone; // For SysTime, LocalTime, etc.
import std.datetime.format;   // For format()

void main() {
    writeln("--- Current Date and Time ---");

    // Get current system time (usually UTC based internally)
    SysTime currentSysTime = Clock.currTime();
    writeln("Current SysTime (UTC based): ", currentSysTime);

    // Convert to local time
    LocalTime currentLocalTime = currentSysTime.to!LocalTime();
    writeln("Current LocalTime: ", currentLocalTime);

    // Get components from LocalTime object
    writeln("\\n--- Components (Local Time) ---");
    writeln("Year: ", currentLocalTime.year);
    writeln("Month: ", currentLocalTime.month);
    writeln("Day: ", currentLocalTime.day);
    writeln("Hour: ", currentLocalTime.hour);
    writeln("Minute: ", currentLocalTime.minute);
    writeln("Second: ", currentLocalTime.second);
    writeln("Millisecond: ", currentLocalTime.fracSecs.total!"msecs");
    writeln("DayOfWeek: ", currentLocalTime.dayOfWeek);
    // Timezone information might require more specific handling

    writeln("\\n--- Formatting ---");
    // ISO Extended Format (YYYY-MM-DDTHH:mm:ss.fff[+-]HH:MM)
    string isoString = currentLocalTime.toISOString();
    writeln("ISO Extended: ", isoString);

    // Custom formatting using std.datetime.format
    // Uses Python's strftime-like codes
    // See: https://dlang.org/phobos/std_datetime_format.html#.format
    string customFormat1 = currentLocalTime.format("%Y-%m-%d %H:%M:%S");
    writeln("Custom ('%Y-%m-%d %H:%M:%S'): ", customFormat1);

    string customFormat2 = currentLocalTime.format("%A, %B %d, %Y at %I:%M:%S %p");
    writeln("Custom Readable: ", customFormat2);

    writeln("\\n--- Unix Epoch Seconds ---");
    // Get seconds since 1970-01-01 00:00:00 UTC
    long epochSeconds = currentSysTime.toUnixTime();
    writeln("Seconds since epoch (UTC): ", epochSeconds);

    // Nanoseconds since epoch
    long epochNanos = currentSysTime.toTimestamp().total!"nsecs";
    writeln("Nanoseconds since epoch (UTC): ", epochNanos);
}

